    max_xor = 0
    for i in range(n + 1):
        for j in range(i + 1, n + 1):
            xor_val = prefix[i] ^ prefix[j]
            if xor_val > max_xor:
                max_xor = xor_val

    lo = 0
    hi = max_xor

    def feasible(x):
        states = [set() for _ in range(k + 1)]
        states[0].add(0)
        for i in range(1, n + 1):
